#include <stdio.h>

struct Broj {
    int vrijednost;
};

int main() {
    struct Broj b;

    FILE *f = fopen("brojevi.dat", "ab");
    if (f == NULL) {
        printf("Greska pri otvaranju datoteke.\n");
        return 1;
    }

    printf("Unesite cijeli broj: ");
    scanf("%d", &b.vrijednost);

    fwrite(&b, sizeof(struct Broj), 1, f);

    fclose(f);

    printf("Broj je dodan u binarnu datoteku.\n");

    return 0;
}
